CREATE TRIGGER simple_customers_insert
INSTEAD OF INSERT ON simple_customers
BEGIN
    INSERT INTO customers (customer_id, name)
    VALUES (NEW.customer_id, NEW.name);
END;

CREATE TRIGGER order_details_insert
INSTEAD OF INSERT ON order_details
BEGIN
    INSERT INTO orders (order_id, customer_id, order_date)
    VALUES (
        NEW.order_id,
        (SELECT customer_id FROM customers WHERE name = NEW.customer),
        DATE('now')
    );

    INSERT INTO order_items (order_id, product_id, quantity)
    VALUES (
        NEW.order_id,
        (SELECT product_id FROM products WHERE product_name = NEW.product_name),
        NEW.quantity
    );
END;

